```javascript
// /vercel/share/v0-project/components/Chatbot.tsx

import { useState } from 'react';
import { Chat } from '@ai-sdk/react';

const Chatbot = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([]);

  const toggleChat = () => {
    setIsOpen(!isOpen);
  };

  const handleSendMessage = async (message) => {
    setMessages((prev) => [...prev, { text: message, sender: 'user' }]);

    const response = await Chat.send({
      model: 'anthropic/claude-opus-4.6',
      messages: [{ role: 'user', content: message }],
      stream: true,
    });

    setMessages((prev) => [...prev, { text: response.content, sender: 'ai' }]);
  };

  return (
    <div className={`fixed bottom-4 right-4 transition-transform ${isOpen ? 'translate-y-0' : 'translate-y-full'}`}>
      <button onClick={toggleChat} className="bg-blue-500 text-white p-2 rounded">
        Chat
      </button>
      {isOpen && (
        <div className="bg-white shadow-lg rounded-lg p-4 mt-2">
          <div className="h-64 overflow-y-auto">
            {messages.map((msg, index) => (
              <div key={index} className={msg.sender === 'user' ? 'text-right' : 'text-left'}>
                <p className={`p-2 rounded ${msg.sender === 'user' ? 'bg-blue-200' : 'bg-gray-200'}`}>
                  {msg.text}
                </p>
              </div>
            ))}
          </div>
          <input
            type="text"
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                handleSendMessage(e.target.value);
                e.target.value = '';
              }
            }}
            className="border rounded p-2 w-full"
            placeholder="Type a message..."
          />
        </div>
      )}
    </div>
  );
};

export default Chatbot;
```

